$id = (int)($data['id'] ?? query('id', 0)); if ($method === 'PUT' || ($method === 'POST' && ($data['_method'] ?? '') === 'PUT')) { db_exec('UPDATE gallery_items SET title=?, item_type=?, media_url=?, category=?, status=? WHERE id=?', [trim((string)$data['title']), trim((string)($data['item_type'] ?? 'image')), trim((string)$data['media_url']), trim((string)($data['category'] ?? 'General')), (int)($data['status'] ?? 1), $id]); respond(['success' => true]); } db_exec('DELETE FROM gallery_items WHERE id=?', [$id]); respond(['success' => true]);
